import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"Onboarding intro (MPG.2)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/onboarding.md","filePath":"guide/onboarding.md","lastUpdated":1782000494000}'),n={name:"guide/onboarding.md"};function i(s,e,d,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="onboarding-intro-mpg-2" tabindex="-1">Onboarding intro (MPG.2) <a class="header-anchor" href="#onboarding-intro-mpg-2" aria-label="Permalink to &quot;Onboarding intro (MPG.2)&quot;">​</a></h1><p>The onboarding intro is the first-run briefing that tells a new player <strong>what to do</strong> before they wander the forest. It appears as a dismissible overlay when a player starts a <strong>fresh run</strong> from the faction picker — not when resuming a save or restarting after win/lose.</p><h2 id="when-it-shows" tabindex="-1">When it shows <a class="header-anchor" href="#when-it-shows" aria-label="Permalink to &quot;When it shows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Entry path</th><th>Intro shown?</th></tr></thead><tbody><tr><td>New Game → faction picker → <strong>Begin</strong></td><td>Yes</td></tr><tr><td><strong>Continue</strong> (loaded save)</td><td>No</td></tr><tr><td>Win/lose <strong>Restart</strong></td><td>No</td></tr><tr><td>Mid-play (no flag)</td><td>No</td></tr></tbody></table><p>The flag lives in <a href="./state-management"><code>appSlice</code></a>: <code>showOnboardingIntro</code>. It is set by <code>startNewGame({ showIntro: true })</code> from the faction-picker commit path and cleared by <code>dismissOnboardingIntro</code>, <code>continueGame</code>, or <code>returnToMenu</code>.</p><h2 id="what-it-contains" tabindex="-1">What it contains <a class="header-anchor" href="#what-it-contains" aria-label="Permalink to &quot;What it contains&quot;">​</a></h2><p><code>OnboardingIntroCard</code> (<code>src/components/OnboardingIntroCard.tsx</code>) surfaces:</p><ul><li>The run objective — raid <code>objectiveTarget</code> caravans (from <code>gameSlice</code>).</li><li>Default controls — WASD move, Shift sprint, Space jump, F attack, M travel, Esc pause (matching <code>src/game/input/bindings.ts</code>).</li><li>Win/lose rules — objective complete vs HP reaching zero (bleeding drains HP).</li></ul><p>Dismiss via <strong>Begin raid</strong> or <strong>Esc</strong>. After dismissal the overlay is gone and the HUD objective counter remains the persistent progress indicator (MPG.1).</p><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="./objective-loop">Objective &amp; win/lose loop</a> — the goal the intro explains.</li><li><a href="./input-system">Input system</a> — binding codes referenced in the card.</li></ul>',11)])])}const b=t(n,[["render",i]]);export{p as __pageData,b as default};
